ps.pstext:
if !IsFeatureImplemented(FEAT_SME2) || !IsFeatureImplemented(FEAT_FP8) then
    EndOfDecode(Decode_UNDEF);
end;
let n : integer = UInt(Zn::'00');
let d : integer = UInt(Zd);

CheckFPMREnabled();
CheckStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV 32;
var result : bits(VL);

let operand1 : bits(VL) = Z{}(n+0);
let operand2 : bits(VL) = Z{}(n+1);
let operand3 : bits(VL) = Z{}(n+2);
let operand4 : bits(VL) = Z{}(n+3);
for e = 0 to elements-1 do
    let element1 : bits(32) = operand1[e*:32];
    let element2 : bits(32) = operand2[e*:32];
    let element3 : bits(32) = operand3[e*:32];
    let element4 : bits(32) = operand4[e*:32];
    result[(4*e + 0)*:8] = FPConvertFP8{8, 32}(element1, FPCR(), FPMR());
    result[(4*e + 1)*:8] = FPConvertFP8{8, 32}(element2, FPCR(), FPMR());
    result[(4*e + 2)*:8] = FPConvertFP8{8, 32}(element3, FPCR(), FPMR());
    result[(4*e + 3)*:8] = FPConvertFP8{8, 32}(element4, FPCR(), FPMR());

end;
Z{VL}(d) = result;
